6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_SURCHARGE = 0.1;
8	const CURSE_SURCHARGE = 0.5;
9	
10	const BASE_PREMIUM: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_PREMIUM = 60;
22	
23	const isBlock = (type: string, count: number): boolean =>
24	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
25	
26	const groupPremium = (type: string, count: number): number =>
27	  isBlock(type, count) ? BLOCK_PREMIUM : BASE_PREMIUM[type] * count;
28	
29	const countByType = (items: Item[]): Map<string, number> => {
30	  const counts = new Map<string, number>();
31	  for (const { type } of items) counts.set(type, (counts.get(type) ?? 0) + 1);
32	  return counts;
33	};
34	
35	const basePremiumForItems = (items: Item[]): number =>
36	  [...countByType(items)].reduce(
37	    (total, [type, count]) => total + groupPremium(type, count),
38	    0,
39	  );
40	
41	const curseSurchargeForItem = (item: Item): number =>
42	  item.cursed ? BASE_PREMIUM[item.type] * CURSE_SURCHARGE : 0;
43	
44	const curseSurchargeForItems = (items: Item[]): number =>
45	  items.reduce((total, item) => total + curseSurchargeForItem(item), 0);
46	
47	const withFirstInsuranceSurcharge = (amount: number): number =>
48	  amount + amount * FIRST_INSURANCE_SURCHARGE;
49	
50	const itemizedPremium = (items: Item[]): number =>
51	  basePremiumForItems(items) + curseSurchargeForItems(items);
52	
53	const quotePremium = ({ items }: QuoteStep): QuoteResult => ({
54	  premium: Math.ceil(
55	    withFirstInsuranceSurcharge(itemizedPremium(items)) + PROCESSING_FEE,
56	  ),
57	});
58	
59	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
60	  results: scenario.steps.map(quotePremium),
61	});
